"""Verify the generated ci.yml behaves identically to the original."""

import re
import sys

VARIANTS = [
    "ios-arm64-metal",
    "ios-simulator-arm64-metal",
    "linux-arm64-egl",
    "linux-arm64-vulkan",
    "linux-x64-egl",
    "linux-x64-vulkan",
    "macos-arm64-egl",
    "macos-arm64-metal",
    "macos-arm64-vulkan",
    "windows-x64-vulkan",
    "windows-x64-wgl",
]


def parse_steps(text):
    """Map step name -> (run command, raw if condition or None)."""
    steps = {}
    for match in re.finditer(
        r"- name: (.+?)\n(?:\s+if: \$\{\{ (.+?) \}\}\n)?\s+run: (.+?)\n",
        text,
    ):
        name, cond, run = match.groups()
        steps[name] = (run, cond)
    return steps


def eval_orig(cond, env):
    if cond is None:
        return True
    if " == " in cond and "&&" not in cond and "!" not in cond:
        return env == cond.split(" == ")[1].strip("'")
    if "contains(matrix.mise_env, 'vulkan')" in cond:
        return "vulkan" in env
    result = True
    for clause in cond.split(" && "):
        clause = clause.strip()
        if clause == "matrix.mise_env != 'macos-arm64-egl'":
            result &= env != "macos-arm64-egl"
        elif clause == "!startsWith(matrix.mise_env, 'ios-')":
            result &= not env.startswith("ios-")
        elif clause == "!startsWith(matrix.mise_env, 'windows-')":
            result &= not env.startswith("windows-")
        elif clause == "!startsWith(matrix.mise_env, 'linux-arm64-')":
            result &= not env.startswith("linux-arm64-")
        elif clause == "startsWith(matrix.mise_env, 'ios-')":
            result &= env.startswith("ios-")
        elif clause == "startsWith(matrix.mise_env, 'macos-')":
            result &= env.startswith("macos-")
        else:
            raise ValueError(f"unhandled clause: {clause}")
    return result


def eval_gen(cond, env):
    if cond is None:
        return True
    match = re.fullmatch(r"(!?)contains\(fromJSON\('(\[.+\])'\), matrix\.mise_env\)", cond)
    assert match, cond
    negate, members = match.groups()
    listed = set(members.strip("[]").replace('"', "").split(","))
    return (env not in listed) if negate else (env in listed)


def parse_matrix(text):
    return dict(re.findall(r"- mise_env: (\S+)\n\s+runner: (\S+)", text))


orig = open("/tmp/opencode/ci.yml.orig").read()
gen = open("/app/.github/workflows/ci.yml").read()

orig_matrix, gen_matrix = parse_matrix(orig), parse_matrix(gen)
assert orig_matrix == gen_matrix, (orig_matrix, gen_matrix)
assert set(orig_matrix) == set(VARIANTS)

orig_steps, gen_steps = parse_steps(orig), parse_steps(gen)
assert set(orig_steps) == set(gen_steps), (
    set(orig_steps) ^ set(gen_steps),
)

failures = []
for name in orig_steps:
    (orig_run, orig_cond), (gen_run, gen_cond) = orig_steps[name], gen_steps[name]
    if orig_run != gen_run:
        failures.append(f"{name}: run differs: {orig_run!r} vs {gen_run!r}")
    for env in VARIANTS:
        if eval_orig(orig_cond, env) != eval_gen(gen_cond, env):
            failures.append(f"{name}: differs on {env}")

# The variants job also has two anonymous `run:` steps (configure). Check the
# fixed scaffolding is identical apart from matrix/conditions/blank lines.
for fixed in [
    "mise run configure",
    "mise run ci:lint",
    "mise run //docs:build",
    "- uses: ./.github/actions/setup-ci-deps",
    "checkout@df4cb1c069e1874edd31b4311f1884172cec0e10",
    "echo '${{ toJSON(needs) }}'",
    "- run: true",
]:
    assert orig.count(fixed) == gen.count(fixed), fixed

if failures:
    print("\n".join(failures))
    sys.exit(1)
print(f"OK: {len(orig_steps)} steps x {len(VARIANTS)} variants behave identically")

